var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"프레데릭 도마.","JPN":"フレドレック・ドマ。","ENG":"Frederick Doma.","TWN":"弗雷德里克·多馬。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"의회는 만장일치로, 그대를 일족의 송곳니로 임명한다.","JPN":"議会は満場一致で、そなたを一族の戦士の牙に任命する。","ENG":"The council unanimously appoints you as the Fang of our tribe.","TWN":"議會一致決定，任命你為一族的獠牙。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그대는 신성한 의무에 따라 북대륙으로 떠나라.","JPN":"そなたは神聖なる義務に従い、北の大陸へと向かえ。","ENG":"Go north and fulfill your divine duty.","TWN":"依照聖務前往北方大陸吧。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 그곳에서 잠들어 있는 잿더미의 여왕을 깨워라.","JPN":"そしてそこに眠っている灰の女王を目覚めさせるのだ。","ENG":"Awaken the Queen of Ashes from her slumber.","TWN":"然後去喚醒沉睡在那裡的灰燼女王。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"일족의 운명은 그대에게 달렸다.","JPN":"一族の運命はそなたにかかっている。","ENG":"The tribe's fate rests in your hands.","TWN":"家族的命運已然掌握在你的手中。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"아, 내 사랑하는 여동생. 오라버니가 돌아왔단다.","JPN":"ああ、愛する妹よ。兄さんが戻ってきた。","ENG":"Oh, my beloved little sister. I have returned.","TWN":"喔，我親愛的妹妹，哥哥回來了。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"으… 그 말투 징그러워, 오빠.","JPN":"うう……その口調、気持ち悪いよ。兄さん。","ENG":"Ugh... Please don’t talk like that. It’s gross.","TWN":"呃…哥，你這語氣真噁心。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"그리고 피냄새 나. 이상해.","JPN":"それに血の匂いがする。何か変。","ENG":"You reek of blood. Gross.","TWN":"而且你身上有血腥味，好奇怪。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그야 흡혈귀에게 피냄새가 나는 건 당연한 일이지.","JPN":"吸血鬼から血の匂いがするのは当たり前だろう？","ENG":"Vampires are supposed to smell of blood.","TWN":"在吸血鬼身上聞到血腥味是理所當然的吧。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"게다가 이 오빠는 전선에서 싸우는 일족의 전사잖니.","JPN":"それにこの兄は前線で戦っている一族の戦士だ。","ENG":"Plus, I'm a warrior who fought in the frontlines of battle for our tribe.","TWN":"而且哥哥我可是在前線作戰的家族戰士啊。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"인간 피냄새 뿐만이 아니니까 그렇지.","JPN":"でも、この血の匂い、人間だけじゃないよね？","ENG":"I’m saying it because it’s not just human blood that I smell.","TWN":"不僅僅是人類的血腥味。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"의회 어르신들이 또 의식이랍시고 염소 피라도 뒤집어씌운 거야?","JPN":"議会の人たちがまた儀式とか言ってヤギの血でも浴びせた？","ENG":"Did the council elders pour goat blood over you as a ritual or something?","TWN":"議會的老傢伙們又在搞什麼儀式，難道又要澆羊血嗎？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 역시 동생의 코는 못 속이겠구나.","JPN":"ふふ、やはり我が妹の鼻は騙せないな。","ENG":"Hah hah, your sense of smell is as keen as ever.","TWN":"呵呵，果然瞞不過你的鼻子啊。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"오늘은 이 오빠가 오는 도중에 늑대인간의 우두머리와 결투를 벌였단다.","JPN":"今日はこの兄が、ここに来る途中でライカンスロープの頭と決闘をしたんだ。","ENG":"Your big brother fought an alpha lycanthrope on his way back home.","TWN":"今天我回來的路上和狼人首領決鬥了。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"와앗! 정말…?!","JPN":"わあっ！　本当に……！？","ENG":"Whaaat?! Really...?!","TWN":"哇啊！真的…？！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"어땠어?! 강했어?!","JPN":"どうだった！？　強かった！？","ENG":"How was it? Strong?!","TWN":"怎麼樣？！很強嗎？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_NPC_NULL_SISTER","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"물론! 그 뾰족한 손톱이 옷깃을 스쳤을 땐 나도 아찔했거든!","JPN":"もちろん！　あの鋭い爪が服をかすめた時には私もぞっとしたんだ！","ENG":"Of course! Her razor-sharp claws had me on my toes!","TWN":"當然！那尖銳的爪牙擦過衣領時，我真的嚇了一跳！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"아하하, 만월의 영기를 받은 늑대인간이랑 싸우다니!","JPN":"あはは、満月の霊気を浴びたライカンスロープと戦うなんて！","ENG":"Ah hah hah! You fought a lycanthrope under a full moon?!","TWN":"啊哈哈，竟然和吸收了月圓靈氣的狼人戰鬥！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"역시 오라버니는 제정신이 아냐! 굉장해!","JPN":"やっぱり兄さんは正気じゃないね！　すごい！","ENG":"You’re crazy! But also amazing!","TWN":"哥哥果然不正常！太厲害了！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"얼른 얘기 더 들려줘!","JPN":"早くもっと聞かせて！","ENG":"C’mon! Tell me more!","TWN":"快快，再講點這樣的事！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"흐음, 유스티스라고 하는구나.","JPN":"ふーん、ユースティスって言うんだね。","ENG":"Hmm... So her name is Eustis.","TWN":"嗯，原來叫尤思蒂斯啊。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"혼혈답게 제법 인간다운 이름이네.","JPN":"混血らしく、結構人間ぽい名前じゃない。","ENG":"I guess it fits as she’s half-human...","TWN":"不愧是混血，名字還蠻像人類的嘛。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"그럼 다음에 또 오빠와 결투하러 찾아오는 거야?","JPN":"じゃあ、後でまた兄さんと決闘しにやってくるの？","ENG":"Then is she going to track you down and ask for a rematch?","TWN":"那之後還會來找哥哥決鬥嗎？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그래. 아직 어린 소녀였으니까, 분명 다음 번엔 더 강해져 있겠지.","JPN":"ああ。まだ少女だったから、きっと今度はもっと強くなってるだろう。","ENG":"I hope so. She’s still young, but she might even be able to beat me next time we meet.","TWN":"會吧。畢竟她還是個小女孩，之後一定會變得更強的。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"너도 기대되지 않니?","JPN":"あなたも楽しみでしょう？","ENG":"I can’t wait! Don’t you agree?","TWN":"你也很期待吧？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DOMA_NPC_NULL_SISTER","text":{"KOREA":"아아, 나도 싸우고 싶다. 누워서 이야기만 듣는 건 지긋지긋해.","JPN":"あ～あ、私も戦いたい。寝込んで話ばっかり聞いているのはもうコリゴリだよ。","ENG":"Ugh... I wanna fight too. I’m tired of only hearing your stories.","TWN":"啊啊，我也想戰鬥。躺著聽故事真是無聊。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};